class Solution:
    def minMoves(self, classroom, energy):
        from collections import deque
        m = len(classroom)
        n = len(classroom[0])
        litter_id = {}
        start = None
        for i in range(m):
            for j in range(n):
                ch = classroom[i][j]
                if ch == 'S':
                    start = (i, j)
                elif ch == 'L':
                    litter_id[(i, j)] = len(litter_id)
        full_mask = (1 << len(litter_id)) - 1
        # Dijkstra-style (all weights 1, but use a visited dict keyed by state)
        import heapq
        si, sj = start
        start_state = (si, sj, 0, energy)
        dist = {start_state: 0}
        pq = [(0, si, sj, 0, energy)]
        while pq:
            d, i, j, mask, e = heapq.heappop(pq)
            if mask == full_mask:
                return d
            if d > dist.get((i, j, mask, e), 1 << 60):
                continue
            if e == 0:
                continue
            for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                ni, nj = i + di, j + dj
                if ni < 0 or ni >= m or nj < 0 or nj >= n:
                    continue
                ch = classroom[ni][nj]
                if ch == 'X':
                    continue
                ne = e - 1
                nmask = mask
                if ch == 'L':
                    nmask |= (1 << litter_id[(ni, nj)])
                if ch == 'R':
                    ne = energy
                state = (ni, nj, nmask, ne)
                nd = d + 1
                if nd < dist.get(state, 1 << 60):
                    dist[state] = nd
                    heapq.heappush(pq, (nd, ni, nj, nmask, ne))
        return -1

