class Solution:
    def minMoves(self, classroom, energy):
        from collections import deque
        m = len(classroom)
        n = len(classroom[0])
        litter_id = {}
        start = None
        for i in range(m):
            for j in range(n):
                ch = classroom[i][j]
                if ch == 'S':
                    start = (i, j)
                elif ch == 'L':
                    litter_id[(i, j)] = len(litter_id)
        full_mask = (1 << len(litter_id)) - 1
        si, sj = start
        if full_mask == 0:
            return 0
        start_state = (si, sj, 0, energy)
        visited = {start_state}
        dq = deque([(si, sj, 0, energy)])
        moves = 0
        while dq:
            for _ in range(len(dq)):
                i, j, mask, e = dq.popleft()
                if e == 0:
                    continue
                for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    ni, nj = i + di, j + dj
                    if ni < 0 or ni >= m or nj < 0 or nj >= n:
                        continue
                    ch = classroom[ni][nj]
                    if ch == 'X':
                        continue
                    ne = e - 1
                    nmask = mask
                    if ch == 'L':
                        nmask |= (1 << litter_id[(ni, nj)])
                    if ch == 'R':
                        ne = energy
                    if nmask == full_mask:
                        return moves + 1
                    state = (ni, nj, nmask, ne)
                    if state not in visited:
                        visited.add(state)
                        dq.append((ni, nj, nmask, ne))
            moves += 1
        return -1

