var minMoves = function(classroom, energy) {
    const m = classroom.length;
    const n = classroom[0].length;
    const litterId = new Map();
    let si = 0, sj = 0;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const ch = classroom[i][j];
            if (ch === 'S') { si = i; sj = j; }
            else if (ch === 'L') litterId.set(i * n + j, litterId.size);
        }
    }
    const fullMask = (1 << litterId.size) - 1;
    if (fullMask === 0) return 0;
    const enc = (i, j, mask, e) => (((i * n + j) * (fullMask + 1) + mask) * (energy + 1) + e);
    const visited = new Set([enc(si, sj, 0, energy)]);
    let queue = [[si, sj, 0, energy]];
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    let moves = 0;
    while (queue.length) {
        const next = [];
        for (const [i, j, mask, e] of queue) {
            if (e === 0) continue;
            for (const [di, dj] of dirs) {
                const ni = i + di, nj = j + dj;
                if (ni < 0 || ni >= m || nj < 0 || nj >= n) continue;
                const ch = classroom[ni][nj];
                if (ch === 'X') continue;
                let ne = e - 1;
                let nmask = mask;
                if (ch === 'L') nmask |= (1 << litterId.get(ni * n + nj));
                if (ch === 'R') ne = energy;
                if (nmask === fullMask) return moves + 1;
                const code = enc(ni, nj, nmask, ne);
                if (!visited.has(code)) {
                    visited.add(code);
                    next.push([ni, nj, nmask, ne]);
                }
            }
        }
        queue = next;
        moves++;
    }
    return -1;
};
